import{_ as e,o as a,c as t,j as r,a as n,a1 as p}from"./chunks/framework.Bp7r_-XI.js";const h=JSON.parse('{"title":"黑魂戒指组","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/7.系列物品/黑魂戒指组.md","filePath":"4.资源分区/7.物品与装备/4.奇物/7.系列物品/黑魂戒指组.md"}'),o={name:"4.资源分区/7.物品与装备/4.奇物/7.系列物品/黑魂戒指组.md"};function i(s,b,l,d,_,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"黑魂戒指组",tabindex:"-1"},[n("黑魂戒指组 "),r("a",{class:"header-anchor",href:"#黑魂戒指组","aria-label":'Permalink to "黑魂戒指组"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),p('<h1 id="黑魂戒指组-1" tabindex="-1">黑魂戒指组 <a class="header-anchor" href="#黑魂戒指组-1" aria-label="Permalink to &quot;黑魂戒指组&quot;">​</a></h1><p>黑魂戒指组<br> 每一个戒指都占据一个戒指位<br> D级戒指</p><p>浓雾戒指（Ring of Fog）<br> 价格：D+500<br> 占据戒指位<br> 白猫雅薇娜赠与其所信赖同伴的神奇戒指。<br> 戒指上纯白的浓雾，看起来宛如珍珠一般。<br> 此戒指具备了能帮助装备者消声匿迹，较不容易遭到敌人察觉的效果。<br> 效果<br> 带上这个戒指的，人物躯体将变得朦胧起来，如同是一道不起眼的雾气，但仔细查看，也并不难发现。说白了，它存在的价值，也不过是对友人信赖的证明！<br> 使用者获得隐秘检定+3DP器械加值，同时获得D级的反侦测能力,这是一个魔幻来源的反侦查效果。</p><p>微小生命戒指（Tiny Being&#39;S Ring）<br> 价格：D+500<br> 占据戒指位<br> 自古传承，附有小小红宝石的戒指，可以让使用者的回复微微增加。<br> 戒指具有各式各样的效力。<br> 若能在旅行途中找到这些戒指，相信必能成为一大助力。<br> 但倘若真的依靠这种戒指，想必路途也会很艰辛吧。<br> 效果：<br> 佩戴者获得1点快速治疗（治疗点20），并获得2点血量上限，只有装备本戒指时才会生效。</p><p>钢铁庇佑戒指<br> 英文：Ring of Steel Protection<br> 价格：D+500<br> 占据戒指位<br> 冒险者在飞龙巢穴找到了这枚戒指。<br> 这是传说的骑士王伦德尔的戒指。<br> 此戒指将赐与装备者钢铁的庇护效力，而提高对物理属性的防御力。<br> 骑士王伦德尔的传说不计其数，据说就连巨大飞龙的爪子也无法确实伤到他。<br> 效果：<br> 佩戴者体积额外提升2，同时获得4点偏斜防御。</p><p>魔法方石戒指<br> 英文：Spell Stoneplate Ring<br> 价格：D+500<br> 占据戒指位<br> 此方石为众所皆知的骑士象征，将赋予装备者面对各种困难的能力。<br> 蓝方石乃是源自于灵魂，可以极大提升装备者的防御力<br> 效果：<br> 佩戴者获得3点力场防御，及2点全能量抗力。</p><p>狂吼龙徽戒指<br> 英文：Bellowing Dragoncrest Ring<br> 价格：D+500<br> 占据戒指位<br> 颁赠给彼海姆的龙学院特优魔法师的特殊戒指。<br> 徽印乃依照不朽古龙的形象设计而成，狂吼龙徽戒指可以提升魔法的威力。<br> 效果：<br> 佩戴者获得4法术强度及【法破】。</p><p>太阳长子戒指<br> 英文：Ring of The Sun&#39;s Firstborn<br> 价格：D+500<br> 占据戒指位<br> 继承阳光的葛温王长男，过去曾戴过的骯脏老旧戒指。<br> 具备提升雷电威力的效果。<br> 太阳的长男虽是战神，却因为太过愚眛而遭神驱逐，一切纪录也随之灰飞烟灭。<br> 现在就连名字也都已经失传。<br> 效果：<br> 佩戴者在造成电击类型能量伤害时，获得5DP器械加值，并额外将1点严重伤害转换为恶性。</p><p>------------------------------------------------------------------------------<br> C级戒指</p><p>狼之戒指<br> 英文：Wolf Ring<br> 价格：C+1000<br> 占据戒指位<br> 葛温王四骑士获赠的特别戒指。<br> 狼戒指乃是由「漫步深渊」的亚尔特留斯所有。<br> 亚尔特留斯有着敌人攻击难以憾动坚韧意志力，当他挥舞起大剑时，据说是所向披靡。<br> 效果：<br> 佩戴者在用于对抗效果的强韧（耐力+生存（专业：强韧））、反射（敏捷+运动（专业：反射））与意志（决心+专注（专业：意志））检定上获得+2附加成功增强加值。<br> 无论佩戴者无论受到怎样的创伤，都不会影响他继续作战，这视为获得B级免疫创伤来源效果的能力。</p><p>狮子戒指<br> 英文：Leo Ring<br> 价格：C+1000<br> 占据：戒指<br> 葛温王四骑士获赠的特别戒指。<br> 狮子戒指乃是由「猎龙者」翁斯坦所有。<br> 此戒指会提升突刺的威力。<br> 据说翁斯坦的十字枪连岩石般的鳞片也能贯穿。<br> 效果：<br> 佩戴者获得的白刃攻击获得超级贯穿特性，并额外获得2点破甲</p><p>鹰眼戒指<br> 英文：Hawk Ring<br> 价格：C+1000<br> 占据：戒指/腰带/饰品<br> 葛温王四骑士获赠的特别戒指。<br> 老鹰戒指乃是由率领大弓队的「鹰眼」巨人戈夫所有。<br> 此戒指会提高人的感知能力。<br> 据说戈夫曾用大弓射下了高空的古龙。<br> 效果：<br> 虽说是戒指，但本身用于巨人的戒指也太过粗大，使用者可以看自身需求，把它当成腰带或者手环来装备。<br> 当装备此戒指时使用者的敏感范围额外提升一倍，并在洞察技能检定上获得2DP器械加值。</p><p>黄蜂戒指<br> 英文：Hornet Ring<br> 价格：C+1000<br> 占据：戒指<br> 葛温王四骑士获赠的特别戒指。<br> 黄蜂戒指乃是由「王的先锋」基亚蓝所有。<br> 此戒指会提升致命攻击力。<br> 据说女骑士基亚蓝曾用短刀歼灭了葛温王的敌人。<br> 效果<br> 当佩戴者在被攻击者背后使用近战攻击对其特殊部位进行攻击时，额外再获得4点固定伤害，并无视5点部位减值。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',15)])])}const f=e(o,[["render",i]]);export{h as __pageData,f as default};
